import re
from pydantic import BaseModel, Field
from typing import Any

class SensitiveDataDetector:
    PII_PATTERNS = [
        r'\b\d{3}-?\d{2}-?\d{4}\b',  # SSN
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',  # Email
        r'\b4[0-9]{12}(?:[0-9]{3})?\b|\b5[1-5][0-9]{14}\b'  # Credit cards
    ]

    @staticmethod
    def scan_pydantic_output(model_instance: BaseModel) -> list[str]:
        leaks = []
        for field_name, value in model_instance.model_dump().items():
            if isinstance(value, str):
                for pattern in SensitiveDataDetector.PII_PATTERNS:
                    matches = re.finditer(pattern, value)
                    for match in matches:
                        leaks.append(f"PII in {field_name}: {match.group()}")
        return leaks

# Usage
class AgentResponse(BaseModel):
    content: str = Field(..., description="Agent output")

response = AgentResponse(content="Contact support@company.com or call 555-123-4567")
leaks = SensitiveDataDetector.scan_pydantic_output(response)
print(leaks)
