class ToolCallAnalyzer:
    SENSITIVE_KEYS = {'api_key', 'token', 'password', 'secret'}

    @staticmethod
    def detect_context_leak(tool_calls: List[Dict[str, Any]]) -> List[str]:
        leaks = []
        for call in tool_calls:
            args = call.get('args', {})
            for key, value in args.items():
                if any(sensitive in key.lower() for sensitive in ToolCallAnalyzer.SENSITIVE_KEYS):
                    leaks.append(f"Sensitive key '{key}' in tool call: {call['name']}")
                elif isinstance(value, str) and len(value) > 50 and 'sk-' in value:
                    leaks.append(f"Likely OpenAI key in tool {call['name']}")
