import re
from typing import Iterator
from pydantic import BaseModel

class StreamingLeakDetector:
    def __init__(self):
        self.pii_pattern = re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b')

    def validate_chunk(self, chunk: str) -> bool:
        return bool(self.pii_pattern.search(chunk))

    def monitor_stream(self, stream: Iterator[str]) -> Iterator[str]:
        for chunk in stream:
            if self.validate_chunk(chunk):
                print(f"🚨 PII DETECTED in chunk: {repr(chunk[:100])}")
            yield chunk

# Simulate Pydantic AI streaming
class StreamingAgentResponse(BaseModel):
    chunks: List[str]

detector = StreamingLeakDetector()
stream_chunks = ["Processing...", "Found email: user@example.com", "Complete."]

for safe_chunk in detector.monitor_stream(iter(stream_chunks)):
