from pydantic import BaseModel, Field, field_validator
from typing import Any

class SafeString(str):
    @classmethod
    def __get_validators__(cls):
        yield cls.validate

    @classmethod
    def validate(cls, v):
        if isinstance(v, str):
            # Mask common PII patterns
            v = v.replace(re.compile(r'\b\d{3}-?\d{2}-?\d{4}\b'), '[SSN]')
            v = re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]', v)
        return v

class SafeAgentResponse(BaseModel):
    content: SafeString
    metadata: dict[str, SafeString] = {}

    @field_validator('content')
    @classmethod
    def mask_sensitive(cls, v: Any) -> str:
        if isinstance(v, str):
            return SafeString(v)
        return v

# Before: exposes PII
raw_response = {"content": "Email support@company.com"}

# After: safe
safe_response = SafeAgentResponse.model_validate(raw_response)
print(safe_response.content)  # "Email [EMAIL]"
