from pydantic import BaseModel, Field, validator
from typing import Dict, Any

class SanitizedToolArgs(BaseModel):
    args: Dict[str, Any]

    @validator('args')
    def sanitize_args(cls, v):
        SENSITIVE_KEYS = {'api_key', 'token', 'password', 'secret'}
        sanitized = {}
        for k, val in v.items():
            if any(sensitive in k.lower() for sensitive in SENSITIVE_KEYS):
                sanitized[k] = '[REDACTED]'
            elif isinstance(val, str) and ('sk-' in val or len(val) > 50):
                sanitized[k] = '[SECRET]'
            else:
                sanitized[k] = val
        return sanitized

# Before nested tool call
raw_tool_call = {
    'name': 'process_payment',
    'args': {'api_key': 'sk-123abc', 'amount': 100}
}

# Sanitized for safe execution
safe_call = SanitizedToolArgs(args=raw_tool_call['args'])
print(safe_call.args)  # {'api_key': '[SECRET]', 'amount': 100}
